import React, { useEffect, useState } from "react";
import {
  Box,
  Typography,
  RadioGroup,
  Radio,
  FormControlLabel,
  Button,
  InputBase,
  Stack,
} from "@mui/material";
import TeamBtns from "../Components/WebSite/TeamBtn";
import ClassBtn from "../Components/WebSite/ClassBtn";
import CustomBtn from "../Components/common/CustomBtn";
import Header from "../Components/common/Header";
import TextField from "@mui/material/TextField";

function WebSite() {
  const ssafyRegion = [
    ["서울", "A"],
    ["대전", "B"],
    ["광주", "C"],
    ["구미", "D"],
    ["부울경", "E"],
    ["기업연계", "S"],
  ];
  const projectChapters = [
    ["공통", "i", 1],
    ["특화", "j", 2],
    ["자율", "k", 3],
  ];

  const [maxTeamNum, setMaxTeamNum] = useState(
    () => parseInt(localStorage.getItem("teamNum"), 10) || 5
  );
  const [selectedRegion, setSelectedRegion] = useState(
    JSON.parse(localStorage.getItem("region"))
  );
  const [selectedClass, setSelectedClass] = useState(
    !isNaN(localStorage.getItem("class"))
      ? Number(localStorage.getItem("class"))
      : null
  );

  const [password, setPassword] = useState(
    localStorage.getItem("password") || null
  );

  const [webhookUrl, setWebhookUrl] = useState(
    localStorage.getItem("webhookUrl") || null
  );

  const [selectedChapter, setSelectedChapter] = useState(() => {
    try {
      JSON.parse(localStorage.getItem("region"));
    } catch (error) {
      setSelectedChapter(projectChapters[1]);
    }
  });

  const decreaseMaxUserCnt = () => {
    setMaxTeamNum((prev) => Math.max(prev - 1, 5));
  };

  const increaseMaxUserCnt = () => {
    setMaxTeamNum((prev) => Math.min(prev + 1, 12));
  };

  //반 선택 버튼
  const handleClassBtn = (index) => {
    setSelectedClass(index);
  };

  //공/특/자 선택
  const handleChapterChange = (event) => {
    const selected = projectChapters.find(
      ([chapterName]) => chapterName === event.target.value
    );
    setSelectedChapter(selected);
  };

  useEffect(() => {
    localStorage.setItem("chapter", JSON.stringify(selectedChapter));
  }, [selectedChapter]);

  //로컬 스토리지 저장
  useEffect(() => {
    localStorage.setItem("teamNum", maxTeamNum);
  }, [maxTeamNum]);

  useEffect(() => {
    localStorage.setItem("region", JSON.stringify(selectedRegion));
  }, [selectedRegion]);

  useEffect(() => {
    localStorage.setItem("class", selectedClass);
  }, [selectedClass]);

  useEffect(() => {
    localStorage.setItem("password", password);
  }, [password]);

  useEffect(() => {
    localStorage.setItem("webhookUrl", webhookUrl);
  }, [webhookUrl]);

  //모든 팀 한번에 열기
  const handleAllOpenBtn = () => {
    if (selectedRegion !== null && selectedClass !== null) {
      for (let i = 0; i < maxTeamNum; i++) {
        let teamCode = `${selectedRegion[1]}${(selectedClass + 1).toString()}${(
          i + 1
        )
          .toString()
          .padStart(2, "0")}`;
        window.open(
          `https://${selectedChapter[1]}12${teamCode}.p.ssafy.io`,
          "_blank"
        );
      }
    }
  };

  //모든 팀 게릿 오픈
  const handleAllGerritOpenBtn = () => {
    if (selectedRegion !== null && selectedClass !== null) {
      for (let i = 0; i < maxTeamNum; i++) {
        let teamCode = `${selectedRegion[1]}${(selectedClass + 1).toString()}${(
          i + 1
        )
          .toString()
          .padStart(2, "0")}`;
        window.open(
          `https://${selectedChapter[1]}12${teamCode}.p.ssafy.io:8989`,
          "_blank"
        );
      }
    }
  };

  //팀 선택 시 버튼
  const handleTeamBtn = (index) => {
    if (selectedRegion !== null && selectedClass !== null) {
      let teamCode = `${selectedRegion[1]}${(selectedClass + 1).toString()}${(
        index + 1
      )
        .toString()
        .padStart(2, "0")}`;
      window.open(
        `https://${selectedChapter[1]}12${teamCode}.p.ssafy.io`,
        "_blank"
      );
    }
  };

  //gerrit 선택시 버튼
  const handleGerrit = (index) => {
    if (selectedRegion !== null && selectedClass !== null) {
      let teamCode = `${selectedRegion[1]}${(selectedClass + 1).toString()}${(
        index + 1
      )
        .toString()
        .padStart(2, "0")}`;
      window.open(
        `https://${selectedChapter[1]}12${teamCode}.p.ssafy.io:8989`,
        "_blank"
      );
    }
  };

  //jira 선택시 버튼
  const handleJira = (index) => {
    if (selectedRegion !== null && selectedClass !== null) {
      let teamCode = `${selectedRegion[1]}${(selectedClass + 1).toString()}${(
        index + 1
      )
        .toString()
        .padStart(2, "0")}`;
      window.open(
        `https://ssafy.atlassian.net/projects/S12P${selectedChapter[2]}1${teamCode}`,
        "_blank"
      );
    }
  };

  //모든 팀 지라 한번에 열기
  const handleAllJiraOpenBtn = () => {
    if (selectedRegion !== null && selectedClass !== null) {
      for (let i = 0; i < maxTeamNum; i++) {
        let teamCode = `${selectedRegion[1]}${(selectedClass + 1).toString()}${(
          i + 1
        )
          .toString()
          .padStart(2, "0")}`;
        window.open(
          `https://ssafy.atlassian.net/projects/S12P${selectedChapter[2]}1${teamCode}`,
          "_blank"
        );
      }
    }
  };

  const handleGitLabOpenBtn = () => {
    window.open(
      `https://lab.ssafy.com/?name=S12P${selectedChapter[2]}1${
        selectedRegion[1]
      }${selectedClass + 1}&sort=name_asc`,
      "_blank"
    );
  };

  //서버 재부팅
  const handleReboot = (index) => {
    if (window.confirm("정말 초기화 하겠습니까?")) {
      // URL이 없을 경우 사용자에게 입력을 요청합니다.
      let url = webhookUrl;
      if (!url || url === "null") {
        url = prompt("웹훅 URL을 입력하세요:");
        if (url) {
          setWebhookUrl(url);
          localStorage.setItem("webhookUrl", webhookUrl); // 입력된 URL을 로컬 스토리지에 저장합니다.
        } else {
          alert("웹훅 URL이 없어 요청을 취소했습니다.");
          return;
        }
      }

      // 팀 코드를 생성합니다.
      let teamCode = `${selectedRegion[1]}${(selectedClass + 1).toString()}${(
        index + 1
      )
        .toString()
        .padStart(2, "0")}`;

      // 전송할 payload를 설정합니다.
      const payload = {
        text: `aws reboot ${selectedChapter[1].toUpperCase()}12${teamCode}`,
      };

      fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      })
        .then((response) => {
          if (response.ok) {
            alert("재부팅 요청이 성공적으로 전송되었습니다.");
          } else {
            throw new Error("웹훅 전송 실패");
          }
        })
        .catch((error) => {
          console.error("웹훅 전송 중 오류:", error);
          alert("재부팅 요청 중 오류 발생! 웹훅 URL을 다시 설정합니다.");

          // 오류 발생 시 웹훅 URL을 재설정
          const newUrl = prompt("새로운 웹훅 URL을 입력하세요:");
          if (newUrl && typeof newUrl === "string") {
            setWebhookUrl(newUrl); // 상태 업데이트
            localStorage.setItem("webhookUrl", newUrl);
          } else {
            alert("유효한 웹훅 URL이 없어 요청을 취소했습니다.");
          }
        });
    }
  };

  //지역 선택 조절
  const handleRegionChange = (event) => {
    const selected = ssafyRegion.find(
      ([regionName]) => regionName === event.target.value
    );
    setSelectedRegion(selected);
    setSelectedClass(null);
  };

  return (
    <>
      {password !== "11gi!" ? (
        <TextField
          label="비밀번호가 뭐게"
          color="error"
          focused
          onKeyDown={(event) => {
            if (event.key === "Enter") {
              const value = event.target.value;
              const correctPassword = "11gi!";

              if (value === correctPassword) {
                setPassword(value);
                localStorage.setItem("password", value);
              } else {
                alert("비밀번호가 맞지 않습니다!");
              }
            }
          }}
          type="password"
        />
      ) : (
        <>
          <Header />
          <Box
            display="flex"
            flexDirection="column"
            alignItems="center"
            justifyContent="center"
            gap={2}
          >
            {/* <ChapterRadioGroup
              selectedChapter={selectedChapter}
              handleChapterChange=
              {handleChapterChange}
            /> */}

            <RadioGroup
              row
              value={selectedChapter ? selectedChapter[0] : ""}
              onChange={handleChapterChange}
            >
              {projectChapters.map(([chapterName], index) => (
                <FormControlLabel
                  key={index}
                  value={chapterName}
                  control={<Radio />}
                  label={
                    <Typography
                      style={{ fontFamily: "Pretendard", fontSize: "14px" }}
                    >
                      {chapterName}
                    </Typography>
                  }
                  labelPlacement="bottom"
                />
              ))}
            </RadioGroup>

            {/* 지역 선택 */}
            {selectedChapter && (
              <RadioGroup
                row
                value={selectedRegion ? selectedRegion[0] : ""}
                onChange={handleRegionChange}
              >
                {ssafyRegion.map(([regionName], index) => (
                  <FormControlLabel
                    key={index}
                    value={regionName}
                    control={<Radio />}
                    label={
                      <Typography
                        style={{ fontFamily: "Pretendard", fontSize: "14px" }}
                      >
                        {regionName}
                      </Typography>
                    }
                    labelPlacement="bottom"
                  />
                ))}
              </RadioGroup>
            )}

            <Box display="flex" gap="0.5rem">
              {selectedRegion && selectedChapter && (
                <ClassBtn
                  selectedRegion={selectedRegion}
                  selectedClass={selectedClass}
                  handleClassBtn={handleClassBtn}
                />
              )}
            </Box>
          </Box>

          {selectedRegion && selectedChapter && selectedClass !== null && (
            <Box
              display="flex"
              alignItems="center"
              justifyContent="center"
              mt={1}
              mb={10}
            >
              <Button
                onClick={decreaseMaxUserCnt}
                disabled={maxTeamNum === 5}
                color="error"
                variant="contained"
              >
                -
              </Button>

              <span
                style={{
                  marginLeft: "18px",
                }}
              >
                팀개수
              </span>
              <InputBase
                value={maxTeamNum}
                readOnly
                inputProps={{
                  min: 8,
                  max: 12,
                  style: {
                    textAlign: "center",
                    fontSize: "24px",
                    width: "48px",
                    color: "purple",
                  },
                }}
              />
              <Button
                onClick={increaseMaxUserCnt}
                disabled={maxTeamNum === 12}
                color="primary"
                variant="contained"
              >
                +
              </Button>
            </Box>
          )}

          <Box display="flex" gap="0.5rem">
            {selectedRegion && selectedChapter && selectedClass !== null && (
              <TeamBtns
                numButtons={maxTeamNum}
                selectedClass={selectedClass}
                selectedRegion={selectedRegion}
                handleTeamBtn={handleTeamBtn}
                handleGerrit={handleGerrit}
                handleJira={handleJira}
                handleReboot={handleReboot}
              />
            )}
          </Box>

          <Box mt={2}>
            {selectedRegion && selectedChapter && selectedClass !== null && (
              <Stack direction="row" spacing={2}>
                <CustomBtn
                  text={"모든 팀 한번에 열기 고?"}
                  btncolor={"purple"}
                  onClick={() => handleAllOpenBtn()}
                />

                <CustomBtn
                  text={"모든 팀 게릿 한번에 열기 고?"}
                  btncolor={"indigo"}
                  onClick={() => handleAllGerritOpenBtn()}
                />

                <CustomBtn
                  text={"모든 팀 지라 한번에 열기 고?"}
                  btncolor={"grey"}
                  onClick={() => handleAllJiraOpenBtn()}
                />

                <CustomBtn
                  text={"Gitlab 모아보기"}
                  btncolor={"cyan"}
                  onClick={() => handleGitLabOpenBtn()}
                />
              </Stack>
            )}
          </Box>
        </>
      )}
    </>
  );
}

export default WebSite;
